package com.kunal.replaybench.controller; import com.kunal.replaybench.model.*; import com.kunal.replaybench.service.ReplayService; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api") public class ReplayController{ private final ReplayService service; public ReplayController(ReplayService s){service=s;} @PostMapping("/scenarios/seed") List<Scenario> seed(){return service.seed();} @GetMapping("/scenarios") List<Scenario> scenarios(){return service.scenarios();} @PostMapping("/evaluations/run") List<EvaluationRun> run(@RequestParam(defaultValue="HYBRID") String agentType){return service.run(agentType);} @GetMapping("/evaluations") List<EvaluationRun> runs(){return service.runs();} @GetMapping("/leaderboard") Map<String,Object> leaderboard(){return service.leaderboard();} }
